%[text] ## Kahsaev embedding using right Heisenberg double
%[text] 
vl=arrayfun(@(~)VirtualLink,zeros(2,2));
vl(1,1).setData(odata={{[-1,2,0],[1,3,0],[-2,-3,0]},[1,-1,-1]})
vl(1,2).setData(odata={{[2,-3,0],[1,3,0],[-1,-2,0]},[-1,-1,1]})
for ii=1:2
    vl(2,ii).setData(odata=vl(1,ii).odata);
    vl(2,ii).convertKnotCompl();
end
disp(vl)
