function Dif = expr(name,N,Op,S)
    %F  Test Kashaev-embedding candidate map phi.
    %
    % Usage:
    %   dif = F(caseID, useCopF, useOppTilde, useS_u, useS_f)
    %
    % Parameters (all integers 0/1 except caseID):
    %   N           : param for borel half
    % Output:
    %   dif : numeric discrepancy of algebra-hom condition
    if name=="KP"
        Z=VectKPAlg.getGenerator;
    elseif name=="cyc"
        Z=CyclicGroupAlg.getGenerator(N);
    elseif name=="sl2+"
        Z=Uqsl2BorelSmall.getGenerator(1/N,"L");
    end
    M=Z.getSC("prod");
    C=Z.getSC("coprod");
    S=Z.getSC("antipode");
    Si=Z.getSC("antipode_inv");
    dim=Z.dim;
    ZD=VectDrinfeldDouble.getGenerator2(Z,"DH");
    ZH=VectHeisenbergDouble.getGenerator2(Z,"HH");
    % prod on D(U)
    M_D=reshape(ZD.getSC("prod"),dim*ones(1,6));
    % prod on H(U)=U^*#U
    M_H=reshape(ZH.getSC("prod"),dim*ones(1,6));
    % prod on H~(U)=U#(U^*)^op
    M_Ht=calcTensorExpression('C{6,4,8}C{3,7,9}M{9,8,2}M{1,7,5}',1:6);
    
    % --- Build phi tensor for the selected candidate ---
    % phi=calcTensorExpression('Si{9,12}M{6,8,2}M{9,10,8}S{11,5}C{1,3,4}C{4,5,6}',[2,1,10,3,12,11]);
    phi=calcTensorExpression('M{3,4,1}C{2,5,6}S{7,6}',[1,2,7,3,4,5]);
    % --- Homomorphism check: phi(xy) == phi(x)phi(y) ---
    % Implement as tensors:
    % LHS = phi * prodD
    % RHS = (prodHtilde^op ⊗ prodH) * tau23 * (phi ⊗ phi)
    %
    % NOTE: exact contraction order depends on your index convention.
    % The following is schematic; replace by your Z.contract/Z.permute calls.
    
    % LHS=calcTensorExpression('M_H{5,6,9,10,13,14}M_H{11,12,7,8,15,16}phi{1,2,5,6,7,8}phi{3,4,9,10,11,12}',[1:4,13:16]);
    LHS=calcTensorExpression('M_Ht{5,6,9,10,13,14}M_H{7,8,11,12,15,16}phi{1,2,5,6,7,8}phi{3,4,9,10,11,12}',[1:4,13:16]);
    RHS=calcTensorExpression('phi{5,6,7,8,9,10}M_D{1,2,3,4,5,6}',[1:4,7:10]);
    Dif=LHS-RHS;
end

